 86→const QUICKLINKS_KEY = 'quicklinks';
 87→
 88→interface StoredQuicklink {
 89→  id: string;
 90→  name: string;
 91→  link: string;
 92→  type: QuicklinkType;
 93→  application?: string;
 94→  tags?: {
 95→    text: string;
 96→    color?: string;
 97→  }[];
 98→  createdAt: string;
 99→}
100→
101→function isStoredTag(value: unknown): value is {
102→  text: string;
103→  color?: string;
104→} {
105→  if (!isRecord(value)) return false;
106→  if (typeof value.text !== 'string') return false;
107→  if ('color' in value && typeof value.color !== 'string') {
108→    return false;
109→  }
110→  return true;
111→}
112→
113→function isQuicklinkType(value: string): value is QuicklinkType {
114→  return value === 'url' || value === 'file' || value === 'deeplink';
115→}
116→
117→function isStoredQuicklinkArray(value: unknown): value is StoredQuicklink[] {
118→  if (!Array.isArray(value)) return false;
119→  return value.every(
120→    v =>
121→      isRecord(v) &&
122→      typeof v.id === 'string' &&
123→      typeof v.name === 'string' &&
124→      typeof v.link === 'string' &&
125→      typeof v.type === 'string' &&
126→      typeof v.createdAt === 'string' &&
127→      (!v.application || typeof v.application === 'string') &&
128→      (!v.tags || (Array.isArray(v.tags) && v.tags.every(isStoredTag))),
129→  );
130→}
131→
132→const TAG_COLOR_NAMES = new Set<string>(Object.keys(TAG_COLOR_HEX));
133→
134→function isTagColor(value: string): value is TagColor {
135→  return TAG_COLOR_NAMES.has(value);
136→}
137→
138→function serializeEntries(entries: QuicklinkEntry[]): StoredQuicklink[] {
139→  return entries.map(e => ({
140→    id: e.id,
141→    name: e.name,
142→    link: e.link,
143→    type: e.type,
144→    application: e.application,
145→    tags: e.tags,
146→    createdAt: e.createdAt.toISOString(),
147→  }));
148→}
149→
150→function deserializeEntries(stored: StoredQuicklink[]): QuicklinkEntry[] {
151→  return stored.map(s => {
152→    const parsed = new Date(s.createdAt);
153→    const createdAt = Number.isNaN(parsed.getTime()) ? new Date() : parsed;
154→    return {
155→      id: s.id,
156→      name: s.name,
157→      link: s.link,
158→      type: isQuicklinkType(s.type) ? s.type : 'url',
159→      application: s.application,
160→      icon: getQuicklinkIcon(isQuicklinkType(s.type) ? s.type : 'url'),
161→      tags: s.tags?.map(t => ({
162→        text: t.text,
163→        color: t.color && isTagColor(t.color) ? t.color : undefined,
164→      })),
165→      createdAt,
166→    };
167→  });
168→}
169→
170→function loadQuicklinks(): QuicklinkEntry[] {
171→  const stored = storageGet(QUICKLINKS_KEY, isStoredQuicklinkArray);
172→  if (stored) return deserializeEntries(stored);
173→  return MOCK_QUICKLINKS;
174→}
175→
176→function saveQuicklinks(entries: QuicklinkEntry[]) {
177→  storageSet(QUICKLINKS_KEY, serializeEntries(entries));
178→}
