194→interface QuicklinkFormState {
195→  name: string;
196→  link: string;
197→  type: QuicklinkType;
198→  application: string;
199→}
200→
201→const INITIAL_FORM: QuicklinkFormState = {
202→  name: '',
203→  link: '',
204→  type: 'url',
205→  application: '',
206→};
207→
208→const TYPE_OPTIONS = [
209→  { label: 'URL', value: 'url' },
210→  { label: 'File Path', value: 'file' },
211→  { label: 'Deep Link', value: 'deeplink' },
212→];
213→
214→interface EditQuicklinkViewProps {
215→  quicklink?: QuicklinkEntry;
216→  onSubmit: (form: QuicklinkFormState) => void;
217→}
218→
219→function EditQuicklinkView({ quicklink, onSubmit }: EditQuicklinkViewProps) {
220→  const [form, setForm] = useState<QuicklinkFormState>(() => {
221→    if (quicklink) {
222→      return {
223→        name: quicklink.name,
224→        link: quicklink.link,
225→        type: quicklink.type,
226→        application: quicklink.application ?? '',
227→      };
228→    }
229→    return INITIAL_FORM;
230→  });
231→  const [errors, setErrors] = useState<
232→    Partial<Record<keyof QuicklinkFormState, string>>
233→  >({});
234→
235→  const handleSubmit = useCallback(() => {
236→    const newErrors: Partial<Record<keyof QuicklinkFormState, string>> = {};
237→    if (!form.name.trim()) {
238→      newErrors.name = 'Name is required';
239→    }
240→    if (!form.link.trim()) {
241→      newErrors.link = 'Link is required';
242→    }
243→    setErrors(newErrors);
244→    if (Object.keys(newErrors).length > 0) return;
245→    onSubmit(form);
246→  }, [form, onSubmit]);
247→
248→  useKeyboardShortcut({ key: 'Enter', meta: true }, handleSubmit);
249→
250→  return (
251→    <Form onSubmit={handleSubmit}>
252→      <FormTextField
253→        label="Name"
254→        value={form.name}
255→        onChange={v => setForm(prev => ({ ...prev, name: v }))}
256→        placeholder="e.g. GitHub Dashboard"
257→        error={errors.name}
258→        autoFocus
259→      />
260→      <FormTextField
261→        label="Link"
262→        value={form.link}
263→        onChange={v => setForm(prev => ({ ...prev, link: v }))}
264→        placeholder="e.g. https://github.com or ~/Documents"
265→        description="Use {query} as placeholder for dynamic input"
266→        error={errors.link}
267→      />
268→      <FormDropdown
269→        label="Type"
270→        value={form.type}
271→        onChange={v => {
272→          if (isQuicklinkType(v)) {
273→            setForm(prev => ({ ...prev, type: v }));
274→          }
275→        }}
276→        options={TYPE_OPTIONS}
277→      />
278→      <FormTextField
279→        label="Open With"
280→        value={form.application}
281→        onChange={v => setForm(prev => ({ ...prev, application: v }))}
282→        placeholder="e.g. Safari (optional)"
283→        description="Application to open the link with"
284→      />
285→    </Form>
286→  );
287→}
