295→function QueryInputView({ quicklink, onSubmit, onCancel }: QueryInputViewProps) {
296→  const [inputValue, setInputValue] = useState('');
297→
298→  const handleSubmit = useCallback(() => {
299→    if (!inputValue.trim()) return;
300→    const resolved = quicklink.link.replace('{query}', encodeURIComponent(inputValue.trim()));
301→    onSubmit(resolved);
302→  }, [inputValue, quicklink.link, onSubmit]);
303→
304→  useKeyboardShortcut({ key: 'Enter', meta: true }, handleSubmit);
305→  useKeyboardShortcut({ key: 'Escape' }, onCancel);
306→
307→  return (
308→    <Form onSubmit={handleSubmit}>
309→      <FormTextField
310→        label="Query"
311→        value={inputValue}
312→        onChange={setInputValue}
313→        placeholder={`Enter query for ${quicklink.name}...`}
314→        description={`Opens: ${quicklink.link.replace('{query}', '<your input>')}`}
315→        autoFocus
316→      />
317→    </Form>
318→  );
319→}
