      {
        title: 'Actions',
        actions: [
          {
            label: 'Open',
            shortcut: <Kbd keys={['↵']} />,
            onClick: handleOpen,
          },
          {
            label: 'Edit',
            shortcut: (
              <Kbd
                keys={[
                  '⌘',
                  'E',
                ]}
              />
            ),
            onClick: handleEdit,
          },
          createCopyAction(
            {
              content: selectedEntry?.link ?? '',
              title: 'Copy Link',
              shortcut: (
                <Kbd
                  keys={[
                    '⌘',
                    'C',
                  ]}
                />
              ),
              hudTitle: 'Link Copied',
            },
            showHUD,
          ),
          {
            label: 'Create Quicklink',
            shortcut: (
              <Kbd
                keys={[
                  '⌘',
                  'N',
                ]}
              />
            ),
            onClick: handleCreate,
          },
        ],
      },
      {
        title: 'Danger Zone',
        actions: [
          {
            label: 'Delete',
            shortcut: (
              <Kbd
                keys={[
                  '⌘',
                  '⌫',
                ]}
              />
            ),
            onClick: handleDelete,
          },
        ],
      },
    ],
    [
      selectedEntry?.link,
      handleOpen,
      handleEdit,
      handleCreate,
      handleDelete,
      showHUD,
    ],
  );

  const activeDescendantId =
    totalItemCount > 0 ? `list-item-${selectedIndex}` : undefined;

  const handleEscape = useCallback(() => {
    if (subView !== 'list') {
      setSubView('list');
      setEditingEntry(undefined);
      setQueryInputEntry(undefined);
    }
  }, [subView]);

  useKeyboardShortcut({ key: 'Escape' }, handleEscape, {
    enabled: subView !== 'list',
  });

  if (subView === 'query-input' && queryInputEntry) {
    return (
      <>
        <SearchBar
          value=""
          onChange={() => {}}
          placeholder={`Query for ${queryInputEntry.name}`}
          breadcrumbs={[
