        strokeLinecap="round"
      />
      <path
        d="M9 7l1.5-1.5a1.75 1.75 0 012.5 2.5L11.5 9.5"
        stroke="currentColor"
        strokeWidth="1.5"
        strokeLinecap="round"
        strokeLinejoin="round"
        fill="none"
      />
      <path
        d="M7 9l-1.5 1.5a1.75 1.75 0 002.5 2.5L9.5 11.5"
        stroke="currentColor"
        strokeWidth="1.5"
        strokeLinecap="round"
        strokeLinejoin="round"
        fill="none"
      />
    </svg>
